def cap(text):
    small = {'de','da','do','das','dos','e','em','no','na','nos','nas','para','por','com','a','o'}
    out = []
    for i, w in enumerate(str(text or '').strip().lower().split()):
        if w in small and i > 0:
            out.append(w)
        elif '-' in w:
            out.append('-'.join(p[:1].upper() + p[1:] for p in w.split('-')))
        else:
            out.append(w[:1].upper() + w[1:])
    return ' '.join(out) or 'Não informado'


def course(value):
    fixes = {
        'LETRAS LÍNGUA BRASILEIRA DE SINAIS FORMAÇÃO DE PROFESSORES': 'Letras Libras - Formação de Professores',
        'LICENCIATURA EM MATEMÁTICA': 'Licenciatura em Matemática',
        'GESTÃO EMPREENDEDORA E INOVAÇÃO DO TURISMO': 'Gestão Empreendedora e Inovação do Turismo',
        'MATEMÁTICA FORMAÇÃO DE PROFESSORES': 'Matemática - Formação de Professores',
    }
    return fixes.get(str(value or '').strip().upper(), cap(value))


def preserve_acronyms(text):
    return (text or '').replace(' Ppl', ' PPL').replace(' ppl', ' PPL')


def unique_headers(headers):
    seen, result = Counter(), []
    for h in headers:
        key = (h or '').lstrip('\ufeff').strip()
        seen[key] += 1
        if key == 'Período' and seen[key] == 1:
            result.append('Período Letivo')
        elif key == 'Período' and seen[key] == 2:
            result.append('Período do Curso')
        elif seen[key] > 1:
            result.append(f'{key} {seen[key]}')
        else:
            result.append(key)
    return result


def parse_csv(text):
    delimiter = ';' if text[:1000].count(';') > text[:1000].count(',') else ','
    rows = list(csv.reader(io.StringIO(text), delimiter=delimiter))
    if not rows:
        return []
    headers = unique_headers(rows[0])
    return [dict((headers[i], row[i].strip() if i < len(row) else '') for i in range(len(headers))) for row in rows[1:] if any(c.strip() for c in row)]


def normalize(row, idx):
    polo = row.get('Polo') or 'Não informado'
    municipio = polo.replace('Polo ', '', 1) if polo.lower().startswith('polo ') else polo
    return {
        'id': idx + 1,
        'matricula': row.get('Matrícula') or '',
        'nome': cap(row.get('Nome')),
        'cpf': row.get('CPF') or '',
        'campus': (row.get('Campus') or 'Não informado').replace('_', ' '),
        'codigo_curso': row.get('Código Curso') or 'Não informado',
        'curso': course(row.get('Descrição do Curso')),
        'email_academico': row.get('Email Acadêmico') or '',
        'email_pessoal': row.get('Email Pessoal') or '',
        'polo': preserve_acronyms(cap(polo)),
        'municipio_polo': preserve_acronyms(cap(municipio)),
        'situacao_curso': cap(row.get('Situação no Curso')),
        'situacao_periodo': cap(row.get('Situação no Período')),
        'periodo_letivo': row.get('Período Letivo') or 'Não informado',
        'periodo_curso': row.get('Período do Curso') or 'Não informado',
    }


def load_records():
    with urllib.request.urlopen(CSV_URL, timeout=30) as response:
        text = response.read().decode('utf-8-sig', errors='replace')
    return [normalize(row, i) for i, row in enumerate(parse_csv(text)) if row.get('Nome') or row.get('Matrícula')]


def ensure_assets():
    os.makedirs(ASSETS_DIR, exist_ok=True)
    if os.path.exists(LOGO_CED): shutil.copyfile(LOGO_CED, os.path.join(ASSETS_DIR, 'logo-ced-uncisal.jpg'))
    if os.path.exists(LOGO_UNCISAL): shutil.copyfile(LOGO_UNCISAL, os.path.join(ASSETS_DIR, 'brasao-uncisal.png'))


